class Solution {
public:
    string predictPartyVictory(string senate) {
        int r = 0;
        int d = 0;
        bool radiant = false;
        bool dire = false;
        for(auto c: senate){
            if(r > 0){
                if(c == 'R'){
                r++;
                radiant = true;
                continue;}
                senate.pop_back();
                r--;
                continue;
            }
            if(d > 0){
                if(c == 'D'){
                d++;
                dire = true;
                continue;}
                senate.pop_back();
                d--;
                continue;
            }
            if(c == 'R'){ 
            r++; 
            radiant = true;}
            else d++;
        }
        if(radiant == true && dire == false) return "Radiant";
        if(radiant == false && dire == true) return "Dire";
        string temp;
        if(radiant && dire)
        temp = predictPartyVictory(senate);
        if (temp == "Radiant") return "Radiant";
        return "Dire";

    }
};

class Solution {
public:
    string predictPartyVictory(string senate) {
        queue<int> radiant, dire;
        int n = senate.size();

        for (int i = 0; i < n; ++i) {
            if (senate[i] == 'R')
                radiant.push(i);
            else
                dire.push(i);
        }
        while (!radiant.empty() && !dire.empty()) {
            int rad = radiant.front();
            int dir = dire.front();
            radiant.pop();
            dire.pop();

            if(rad < dir){
                radiant.push(n+rad);
            }
            else{
                dire.push(n+dir);
            }

        }
        if(radiant.empty())
        return "Dire";
        return "Radiant";


    }
};
